   451→#define DWARF2OUT_ARRAY_DESCR_INFO_MAX_DIMEN 16
   452→
   453→struct array_descr_info
   454→{
   455→  int ndimensions;
   456→  enum array_descr_ordering ordering;
   457→  tree element_type;
   458→  tree base_decl;
   459→  tree data_location;
   460→  tree allocated;
